def base32_encode(b):
    chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567'
    e = ''
    for i in range(0, len(b)):
        e += chars[ord(b[i]) & 31]
    return ''.join([e[i:i+5] for i in range(0, len(e), 5)])

def get_random_bytes(n):
    from os import urandom
    return urandom(n)

def generate_totp(secret):
    time = int(time.time()) // 30
    secret = base64.b32decode(secret, True)
    hm = hmac.new(secret, struct.pack('>Q', time), hashlib.sha1).digest()
    o = hm[-1] & 0xF
    code = struct.unpack_from('>I', hm, o)[0] & 0x7fffffff
    return str(code)[-6:].zfill(6)

def validate_totp(secret, totp):
    current_time = time.mktime((datetime.now()).timetuple()) // 30
    otp = generate_totp(secret)
    if otp == totp and int(generate_totp(secret)) == int(otp):
        return True
    else:
        return False

def create_qrcode(secret, label='Account', issuer="MyCompany"):
    provisioning_uri = 'otpauth://totp/{0}?secret={1}&issuer={2}'.format(label, secret, issuer)
